import json
from pathlib import Path
import sys

try:
    from corems.data_structure.ms_spec import MsSpectra
    from corems.encapsulation.factory import MSFileFactory
    from corems.encapsulation.params import MSParameters
except ImportError:
    sys.exit('CoreMS not installed')

spectrum_path = '{inputs.spectrum_file}'
if not Path(spectrum_path).exists():
    sys.exit(f'Spectrum file not found: {spectrum_path}')

try:
    ms_file = MSFileFactory.mzML_reader(spectrum_path) if spectrum_path.endswith('.mzML') else MSFileFactory.bruker_reader(spectrum_path)
    spectra = ms_file.spectra if hasattr(ms_file, 'spectra') else [ms_file]
except Exception as e:
    sys.exit(f'Failed to load spectrum: {e}')

results = []
for spec in (spectra if isinstance(spectra, list) else [spectra]):
    if not spec or not hasattr(spec, 'peaks'):
        continue

    peaks_before = len(spec.peaks) if spec.peaks else 0
    ionization_mode = getattr(spec, 'polarity', 'unknown')

    method_name = None
    if peaks_before > 100:
        method_name = 'relative_abundance'
        threshold = 0.01
    elif peaks_before > 50:
        method_name = 'signal_noise'
        threshold = 3.0
    else:
        method_name = 'log'
        threshold = 1.0

    if hasattr(spec, 'filter_by_mz'):
        try:
            spec.filter_by_mz(0, 1000)
        except:
            pass

    peaks_after = len(spec.peaks) if spec.peaks else peaks_before

    results.append({
        'task_id': '{task_id}',
        'method_name': method_name,
        'ionization_mode': ionization_mode,
        'peaks_retained': peaks_after
    })

with open('noise_threshold_dispatch.json', 'w') as f:
    json.dump(results if results else [{'task_id': '{task_id}', 'method_name': 'log', 'ionization_mode': 'unknown', 'peaks_retained': 0}], f, indent=2)

print('Output written to noise_threshold_dispatch.json')
